package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterTest {

    private CSVPrinter printer;
    private Appendable out;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintComment_CommentingDisabled() throws IOException {
        when(format.isCommentingEnabled()).thenReturn(false);

        printer.printComment("any comment");

        verify(format).isCommentingEnabled();
        verifyNoMoreInteractions(out);
    }

    @Test
    void testPrintComment_NewRecordTrue_NoLineBefore() throws IOException {
        when(format.isCommentingEnabled()).thenReturn(true);
        when(format.getCommentStart()).thenReturn('#');

        // newRecord is true by default, no println() before comment start
        printer.printComment("abc");

        // Verify out.append called with comment start and space
        verify(out).append('#');
        verify(out).append(' ');
        verify(out).append('a');
        verify(out).append('b');
        verify(out).append('c');
        // Verify println called once at the end (prints a newline)
        verify(out, times(2)).append('\n'); // println() appends newline twice because of println() calls in printComment

        // Because println() is public and appends newline, we verify at least once
    }

    @Test
    void testPrintComment_NewRecordFalse_LineBefore() throws IOException {
        when(format.isCommentingEnabled()).thenReturn(true);
        when(format.getCommentStart()).thenReturn('#');

        // Set newRecord to false via reflection to test println() before comment start
        setField(printer, "newRecord", false);

        // We spy on printer to verify println() call
        CSVPrinter spyPrinter = spy(printer);
        doNothing().when(spyPrinter).println();

        spyPrinter.printComment("abc");

        verify(spyPrinter).println();
        verify(out).append('#');
        verify(out).append(' ');
        verify(out).append('a');
        verify(out).append('b');
        verify(out).append('c');
        verify(spyPrinter, times(2)).println();
    }

    @Test
    void testPrintComment_WithCRAndLF() throws IOException {
        when(format.isCommentingEnabled()).thenReturn(true);
        when(format.getCommentStart()).thenReturn('#');

        // comment with CRLF and LF
        String comment = "a\r\nb\nc\r\n";

        printer.printComment(comment);

        // Verify out.append called with comment start and space multiple times
        ArgumentCaptor<Character> captor = ArgumentCaptor.forClass(Character.class);

        verify(out, atLeastOnce()).append(captor.capture());

        // Check that comment start and spaces are appended multiple times (for each new line)
        long commentStartCount = captor.getAllValues().stream().filter(c -> c == '#').count();
        long spaceCount = captor.getAllValues().stream().filter(c -> c == ' ').count();

        assertTrue(commentStartCount >= 3);
        assertTrue(spaceCount >= 3);

        // Verify characters a,b,c appended
        verify(out).append('a');
        verify(out).append('b');
        verify(out).append('c');
    }

    private static void setField(Object target, String fieldName, Object value) {
        try {
            java.lang.reflect.Field field = CSVPrinter.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            field.set(target, value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
